mapper.select:
/* adm-master-ctg-sql-oracle.xml - selectCtgCount */ SELECT COUNT(1) FROM ( SELECT '0' AS CHK , T.OWKEY , OW.OWNM , T.CTGNM AS CTGTREE , T.CTGKEY , T.CTGLV AS CTGLEVEL , T.CTGNM , T.UPPERCTGKEY , MC.URKEY , MC.INSERTDATE , MC.UPDATEDATE , MC.INSERTURKEY , MC.UPDATEURKEY , MC.CLOSDATE , T.DELYN FROM ( WITH RECURSIVE ctg_tree AS ( SELECT OWKEY::VARCHAR AS OWKEY , ''::VARCHAR AS CTGLV , ''::VARCHAR AS CTGKEY , ''::VARCHAR AS CTGNM , ''::VARCHAR AS UPPERCTGKEY , ''::VARCHAR AS DELYN , ARRAY[''::VARCHAR] AS path , 0 AS depth FROM TADMIN_MST_ICGR WHERE 1=0 UNION ALL SELECT OWKEY::VARCHAR , '0'::VARCHAR AS CTGLV , ICGRPKEY::VARCHAR AS CTGKEY , ICGRPNM::VARCHAR AS CTGNM , NULL::VARCHAR AS UPPERCTGKEY , 'N'::VARCHAR AS DELYN , ARRAY[ICGRPKEY::VARCHAR] AS path , 1 AS depth FROM TADMIN_MST_ICGR WHERE OWKEY = #{owkey} UNION ALL SELECT CT.OWKEY::VARCHAR , CT.CTGLV::VARCHAR , CT.CTGKEY::VARCHAR , CT.CTGNM::VARCHAR , (CASE WHEN CT.CTGLV='1' THEN CT.ICGRPKEY ELSE CT.UPPERCTGKEY END)::VARCHAR AS UPPERCTGKEY , CT.DELYN::VARCHAR , p.path || CT.CTGKEY::VARCHAR , p.depth + 1 FROM TADMIN_MST_CTG CT INNER JOIN ctg_tree p ON CT.UPPERCTGKEY = p.CTGKEY WHERE CT.OWKEY = #{owkey} AND CT.DELYN = 'N' ) SELECT * FROM ctg_tree ) T LEFT OUTER JOIN TADMIN_MST_CTG MC ON T.OWKEY = MC.OWKEY AND T.CTGKEY = MC.CTGKEY INNER JOIN TADMIN_MST_OW OW ON T.OWKEY = OW.OWKEY
AND #{SEARCH_CONDITION}
ORDER BY T.path, MC.UPDATEDATE DESC, T.CTGKEY )

/* adm-master-ctg-sql-oracle.xml - selectCtg */ #{GRIDPAGING_ROWNUMTYPE_TOP} SELECT '0' AS CHK , T.OWKEY , OW.OWNM , T.CTGNM AS CTGTREE , T.CTGKEY , T.CTGLV AS CTGLEVEL , T.CTGNM , T.UPPERCTGKEY , MC.URKEY , T.INSERTDATE , T.UPDATEDATE , T.INSERTURKEY , T.UPDATEURKEY , T.CLOSDATE , T.DELYN FROM ( WITH RECURSIVE ctg_tree2 AS ( SELECT OWKEY::VARCHAR AS OWKEY , ''::VARCHAR AS CTGLV , ''::VARCHAR AS CTGKEY , ''::VARCHAR AS CTGNM , ''::VARCHAR AS UPPERCTGKEY , ''::VARCHAR AS DELYN , INSERTDATE , UPDATEDATE , INSERTURKEY , UPDATEURKEY , CLOSDATE , ARRAY[''::VARCHAR] AS path , 0 AS depth FROM TADMIN_MST_ICGR WHERE 1=0 UNION ALL SELECT OWKEY::VARCHAR , '0'::VARCHAR AS CTGLV , ICGRPKEY::VARCHAR AS CTGKEY , ICGRPNM::VARCHAR AS CTGNM , NULL::VARCHAR AS UPPERCTGKEY , 'N'::VARCHAR AS DELYN , INSERTDATE , UPDATEDATE , INSERTURKEY , UPDATEURKEY , CLOSDATE , ARRAY[ICGRPKEY::VARCHAR] AS path , 1 AS depth FROM TADMIN_MST_ICGR WHERE OWKEY = #{owkey} UNION ALL SELECT CT.OWKEY::VARCHAR , CT.CTGLV::VARCHAR , CT.CTGKEY::VARCHAR , CT.CTGNM::VARCHAR , (CASE WHEN CT.CTGLV='1' THEN CT.ICGRPKEY ELSE CT.UPPERCTGKEY END)::VARCHAR AS UPPERCTGKEY , CT.DELYN::VARCHAR , CT.INSERTDATE , CT.UPDATEDATE , CT.INSERTURKEY , CT.UPDATEURKEY , CT.CLOSDATE , p.path || CT.CTGKEY::VARCHAR , p.depth + 1 FROM TADMIN_MST_CTG CT INNER JOIN ctg_tree2 p ON CT.UPPERCTGKEY = p.CTGKEY WHERE CT.OWKEY = #{owkey} AND CT.DELYN = 'N' ) SELECT * FROM ctg_tree2 ) T LEFT OUTER JOIN TADMIN_MST_CTG MC ON T.OWKEY = MC.OWKEY AND T.CTGKEY = MC.CTGKEY INNER JOIN TADMIN_MST_OW OW ON T.OWKEY = OW.OWKEY
AND #{SEARCH_CONDITION}
ORDER BY #{colName} DESC
ORDER BY #{colName} ASC
ORDER BY T.path, MC.UPDATEDATE DESC, T.CTGKEY
#{GRIDPAGING_ROWNUMTYPE_BOTTOM}

mapper.insert:
		/* adm-master-ctg-sql-oracle.xml - insertTAdminMstCtg */
		INSERT INTO TADMIN_MST_CTG	(
			 OWKEY
			,CTGKEY
			,CTGLV
			,CTGNM
			,UPPERCTGKEY
			,URKEY
			,INSERTDATE
			,INSERTURKEY
			,UPDATEDATE
			,UPDATEURKEY
			,CLOSDATE
			,ICGRPKEY
		 )
		VALUES	(
			 #{owkey}
			,#{ctgkey}
			,#{ctglv}
			,#{ctgnm}
			,COALESCE(#{upperctgkey}, 'DIR')
			,#{urkey}
			,#{sysdate}
			,#{surkey}
			,#{sysdate}
			,#{surkey}
            ,#{closdate}
			,#{icgrpkey}
		)

mapper.update:
/* adm-master-ctg-sql-oracle.xml - updateTAdminMstCtg */
UPDATE 	TADMIN_MST_CTG
   SET	 CTGNM 		  	  = #{ctgnm}
		,UPPERCTGKEY 		  = #{upperctgkey}
		,URKEY 				  = #{urkey}
		,UPDATEDATE   		  = #{sysdate}
		,UPDATEURKEY  		  = #{surkey}
WHERE OWKEY 		 = #{owkey}
AND   CTGKEY   		 = #{ctgkey}
AND   CTGLV 		 = #{ctglv}

mapper.delete:
/* adm-master-ctg-sql-oracle.xml - deleteTAdminMstCtg */
UPDATE  TADMIN_MST_CTG
SET      DELYN 				= 'Y'
		,CLOSDATE		= #{closdate}
		,UPDATEDATE   		  = #{sysdate}
		,UPDATEURKEY  		  = #{surkey}
WHERE OWKEY 		 = #{owkey}
AND   CTGKEY   		 = #{ctgkey}
AND   CTGLV 		 = #{ctglv}

